operations.reducer:
state.title = action.input.title || state.title;
state.code = action.input.code || state.code;
state.summary = action.input.summary || state.summary;
state.briefing = action.input.briefing || state.briefing;
state.eligibilityCriteria = action.input.eligibilityCriteria || state.eligibilityCriteria;
state.evaluationCriteria = action.input.evaluationCriteria || state.evaluationCriteria;
state.status = action.input.status || state.status;
state.deadline = action.input.deadline || state.deadline;
state.tags = action.input.tags || state.tags;
if (action.input.budgetRange) {
  state.budgetRange = {
    min: action.input.budgetRange.min ?? state.budgetRange?.min ?? null,
    max: action.input.budgetRange.max ?? state.budgetRange?.max ?? null,
    currency: action.input.budgetRange.currency ?? state.budgetRange?.currency ?? null,
  };
}

operations.schema:
input AddContextDocumentInput {
  rfpId: OID!
  name: String!
  url: URL!
}

operations.reducer:
if (action.input.name === undefined || action.input.name === null) {
  throw new Error('Context document name is required');
}
if (action.input.url === undefined || action.input.url === null) {
  throw new Error('Context document URL is required');
}
state.contextDocuments.push({
  name: action.input.name,
  url: action.input.url,
});

operations.schema:
input RemoveContextDocumentInput {
  rfpId: OID!
  name: String!
}

operations.reducer:
if (action.input.name === undefined || action.input.name === null) {
  throw new Error('Context document name is required');
}
state.contextDocuments = state.contextDocuments.filter(
  (document) => document.name !== action.input.name,
);

if (action.input.title === undefined || action.input.title === null) {
  throw new Error('Proposal title is required');
}
if (action.input.summary === undefined || action.input.summary === null) {
  throw new Error('Proposal summary is required');
}
if (action.input.budgetEstimate === undefined || action.input.budgetEstimate === null) {
  throw new Error('Proposal budget estimate is required');
}
if (action.input.paymentTerms === undefined || action.input.paymentTerms === null) {
  throw new Error('Proposal payment terms are required');
}
if (action.input.proposalStatus === undefined || action.input.proposalStatus === null) {
  throw new Error('Proposal status is required');
}
state.proposals.push({
  title: action.input.title,
  summary: action.input.summary,
  budgetEstimate: action.input.budgetEstimate,
  paymentTerms: action.input.paymentTerms,
  proposalStatus: action.input.proposalStatus,
  submittedby: action.input.submittedby || null,
  id: action.input.id,
});

operations.schema:
input ChangeProposalStatusInput {
  proposalId: OID!
  status: RfpProposalStatus!
}

operations.reducer:
if (action.input.proposalId === undefined || action.input.proposalId === null) {
  throw new Error('Proposal ID is required');
}
if (action.input.status === undefined || action.input.status === null) {
  throw new Error('Proposal status is required');
}
state.proposals = state.proposals.map((proposal) => {
  if (proposal.id === action.input.proposalId) {
    return { ...proposal, proposalStatus: action.input.status };
  }
  return proposal;
});

operations.schema:
input RemoveProposalInput {
  rfpId: OID!
  id: OID!
}

operations.reducer:
if (action.input.id === undefined || action.input.id === null) {
  throw new Error('Proposal ID is required');
}
state.proposals = state.proposals.filter((proposal) => proposal.id !== action.input.id);
